import React from "react";
import { useLocation, useNavigate } from "react-router-dom";

export default function RequestDetails() {
  const { state } = useLocation();
  const navigate = useNavigate();
  const order = state?.request;

  if (!order) {
    return <p>Request details not available.</p>;
  }

  const settings = order.perPageSettings || [];

  const intOrZero = val => {
    const x = parseInt(val);
    return isNaN(x) ? 0 : x;
  };

  const pageCount = order.pages || 0;

  // Create a map from settings for fast lookup
  const pageSettingsMap = {};
  settings.forEach(s => {
    pageSettingsMap[s.page] = s;
  });

  return (
    <div className="p-6 bg-gray-50 min-h-screen">
      <button
        onClick={() => navigate(-1)}
        className="mb-6 text-blue-600 hover:text-blue-800 transition duration-200 underline"
      >
        ← Back
      </button>

      <div className="bg-white shadow-lg rounded-xl p-6">
        <h2 className="text-3xl font-bold text-indigo-800 mb-6">📝 Request Details</h2>

        <div className="grid sm:grid-cols-2 gap-4 text-gray-700 mb-6">
          <p><strong>ID:</strong> <code>{order.id}</code></p>
          <p><strong>Student:</strong> {order.studentName || "Unknown"}</p>
          <p><strong>Submitted:</strong> {order.timestamp ? new Date(order.timestamp.seconds * 1000).toLocaleString() : "Unknown"}</p>
          <p><strong>Status:</strong> {order.status}</p>
          <p><strong>Total Price:</strong> ₹{intOrZero(order.price)}</p>
        </div>

        <div className="mb-6">
          <strong className="text-gray-800">📄 File:</strong>{" "}
          <a
            href={order.fileUrl}
            target="_blank"
            rel="noopener noreferrer"
            className="text-blue-600 underline hover:text-blue-800 transition"
          >
            View / Download
          </a>
        </div>

        <section className="mt-6">
          <h3 className="text-xl font-semibold text-indigo-700 mb-4">🧾 Print Settings</h3>
          <div className="grid grid-cols-3 sm:grid-cols-5 md:grid-cols-7 lg:grid-cols-9 gap-3">
            {Array.from({ length: pageCount }, (_, i) => {
              const pageNum = i + 1;
              const setting = pageSettingsMap[pageNum] || { type: "B/W", copies: 1 };

              const bgColor =
                setting.type === "Color" ? "bg-red-400" : "bg-gray-300";
              const textColor =
                setting.type === "Color" ? "text-white" : "text-black";

              return (
                <div
                  key={pageNum}
                  className={`rounded-lg shadow-md p-2 flex flex-col items-center justify-center ${bgColor} ${textColor}`}
                >
                  <span className="text-sm font-bold">Page {pageNum}</span>
                  <span className="text-xs">🖨 {setting.copies} copy</span>
                  <span className="text-xs">{setting.type}</span>
                </div>
              );
            })}
          </div>

          <div className="mt-6 space-y-2 text-sm text-gray-700">
            <p><strong>Copies (batch):</strong> {order.copies ?? "N/A"}</p>
            <p><strong>Print Type:</strong> {order.printType ?? "N/A"}</p>
            <p><strong>Color Option:</strong> {order.color ?? "N/A"}</p>
            <p><strong>Binding:</strong> {order.binding ? "Yes" : "No"}</p>
            <p><strong>Punch:</strong> {order.punch ? "Yes" : "No"}</p>
            <p><strong>Staple:</strong> {order.staple ? "Yes" : "No"}</p>
          </div>
        </section>
      </div>
    </div>
  );
}
